import { useEffect } from "react"
import { getAll, getImageUrl } from "../api/robotApi"
import { useDispatch, useSelector } from "react-redux"
import { set_arr_robots } from "../redux/dataReducerRobot";
import { add } from "../redux/dateReducerCart";
import './shop.css';

function Shop() {
    const dis = useDispatch();

    //שולף מתוך מאגר מקומי
    //הצגת כל התלמידות
    const arr = useSelector(s => s.robot?.arr_robots || [])  
    
    //בעת טעינת הקומפוננטה
    useEffect(() => {
        const controller = new AbortController();
        const { signal } = controller;

        async function getData() {
            //רק אם המערך ריק
            if (arr.length == 0) {
                //תבצע קריאת שרת
                try {
                    const arr_robots = await getAll({ signal })
                    
                    //מעדכן את המערך המשותף לתשובה מהשרת
                    dis(set_arr_robots(arr_robots))
                } catch (error) {
                    if (error.name !== 'AbortError') {
                        console.error('Failed to fetch robots:', error);
                    }
                }
            }
        }
        getData();

        return () => {
            controller.abort();
        };
    }, [arr.length, dis])

    return (
        <div className="shop-page-container">
            <h1 className="shop-title">גלריית הרובוטים</h1>

            <div className="products-grid">
                {
                    arr.map(s =>
                        <div key={s._id} className="robot-card">
                            
                            <div className="image-container">
                                <img src={getImageUrl(s.img)} alt={s.robotName} />
                            </div>

                            <div className="card-content">
                                <h2 className="robot-name">{s.robotName}</h2>
                                <h3 className="robot-price">{s.price} ₪</h3>
                                <h3 className="stock-info">במלאי: {s.amountInStock} יחידות</h3>
                                
                                <div className="card-actions">
                                    <button className="btn-details">פרטים נוספים</button>
                                    <button className="btn-add-cart" onClick={() => {
                                        dis(add(s))
                                    }}>הוסף לסל</button>
                                </div>
                            </div>
                        </div>
                    )
                }
            </div>
        </div>
    )
}

export default Shop;
